import { __decorate } from "tslib";
import { CommonModule } from '@angular/common';
import { ChangeDetectionStrategy, Component, Input, ViewEncapsulation, } from '@angular/core';
import { LucideAngularModule, Minus, TrendingDown, TrendingUp } from 'lucide-angular';
import { OriSkeletonComponent } from '../skeleton/skeleton.component';
let nextId = 0;
/**
 * Affiche une métrique chiffrée (KPI) : valeur principale, libellé,
 * tendance optionnelle. Pas de conteneur intégré : l'app choisit (Card,
 * plain div, etc.).
 */
let OriStatisticComponent = class OriStatisticComponent {
    constructor() {
        this.variant = 'default';
        this.loading = false;
        this.formatNumber = true;
        this.locale = 'fr-FR';
        this.labelId = `pf-stat-${++nextId}`;
    }
    get rootClasses() {
        const base = 'ori-statistic';
        return this.variant === 'default' ? base : `${base} ori-statistic--${this.variant}`;
    }
    get formattedValue() {
        if (typeof this.value === 'number' && this.formatNumber) {
            return new Intl.NumberFormat(this.locale, this.numberFormatOptions).format(this.value);
        }
        return String(this.value ?? '');
    }
    get trendIcon() {
        if (!this.trend)
            return Minus;
        if (this.trend.direction === 'up')
            return TrendingUp;
        if (this.trend.direction === 'down')
            return TrendingDown;
        return Minus;
    }
    get trendClasses() {
        if (!this.trend)
            return 'ori-statistic__trend';
        const positive = this.trend.positive ?? 'up';
        let tone;
        if (this.trend.direction === 'flat')
            tone = 'flat';
        else
            tone = this.trend.direction === positive ? 'up' : 'down';
        return `ori-statistic__trend ori-statistic__trend--${tone}`;
    }
    static { this.propDecorators = {
        label: [{ type: Input, args: [{ required: true },] }],
        value: [{ type: Input, args: [{ required: true },] }],
        prefix: [{ type: Input }],
        suffix: [{ type: Input }],
        trend: [{ type: Input }],
        variant: [{ type: Input }],
        loading: [{ type: Input }],
        formatNumber: [{ type: Input }],
        locale: [{ type: Input }],
        numberFormatOptions: [{ type: Input }]
    }; }
};
